static bool sensors_fresh(const controller_t *controller, uint32_t now_ms)
{
    if (!controller->has_valid_turbidity) {
        return false;
    }
    if (!controller->has_valid_level) {
        return false;
    }
    if (now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    if (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    return true;
}

static bool level_sufficient(const controller_t *controller)
{
    return controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL;
}

static bool level_complete(const controller_t *controller)
{
    return controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL;
}

static void apply_filter_on(controller_t *controller)
{
    controller->filter_on = true;
    controller->drain_open = false;
}

static void apply_drain_closed(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
}

static void apply_drain_open(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = true;
}

static void reset_clear_streak(controller_t *controller)
{
    controller->clear_streak_count = 0;
}

static void increment_clear_streak(controller_t *controller)
{
    controller->clear_streak_count++;
}

static bool turbidity_clear(const controller_t *controller)
{
    return controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU;
}

static bool turbidity_cloudy(const controller_t *controller, int threshold)
{
    return controller->last_turbidity_ntu > threshold;
}

static void enter_filtering(controller_t *controller)
{
    controller->state = CONTROLLER_STATE_FILTERING;
    apply_filter_on(controller);
}

static void enter_settling(controller_t *controller, uint32_t now_ms)
{
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = now_ms;
    apply_drain_closed(controller);
}

static void enter_draining(controller_t *controller)
{
    controller->state = CONTROLLER_STATE_DRAINING;
    apply_drain_open(controller);
}

static void enter_complete(controller_t *controller)
{
    controller->state = CONTROLLER_STATE_COMPLETE;
    apply_drain_closed(controller);
}

static bool settling_elapsed(const controller_t *controller, uint32_t now_ms)
{
    return (now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    bool timeout = false;

    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        timeout = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (timeout || !sensors_fresh(controller, input.now_ms)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
    } else {
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_IDLE:
            if (level_sufficient(controller)) {
                enter_filtering(controller);
            } else if (level_complete(controller)) {
                enter_complete(controller);
            }
            break;

        case CONTROLLER_STATE_FILTERING:
            if (level_complete(controller)) {
                enter_complete(controller);
            } else if (!level_sufficient(controller)) {
                apply_drain_closed(controller);
            } else {
                if (turbidity_clear(controller)) {
                    increment_clear_streak(controller);
                    if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                        enter_settling(controller, input.now_ms);
                    }
                } else {
                    reset_clear_streak(controller);
                }
            }
            break;

        case CONTROLLER_STATE_SETTLING:
            if (level_complete(controller)) {
                enter_complete(controller);
            } else if (!level_sufficient(controller)) {
                apply_drain_closed(controller);
            } else {
                if (turbidity_cloudy(controller, CONTROLLER_SETTLING_RESET_THRESHOLD_NTU)) {
                    reset_clear_streak(controller);
                    enter_filtering(controller);
                } else if (settling_elapsed(controller, input.now_ms) && turbidity_clear(controller)) {
                    enter_draining(controller);
                }
            }
            break;

        case CONTROLLER_STATE_DRAINING:
            if (level_complete(controller)) {
                enter_complete(controller);
            } else if (!level_sufficient(controller)) {
                apply_drain_closed(controller);
            } else {
                if (turbidity_cloudy(controller, CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU)) {
                    reset_clear_streak(controller);
                    enter_filtering(controller);
                }
            }
            break;

        case CONTROLLER_STATE_COMPLETE:
            apply_drain_closed(controller);
            break;
        }
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

